import { useState, useLayoutEffect, useRef } from 'react';
import { CloseIcon, SendIcon } from '../ui/Icons';

/**
 * @param {{
 *   isOpen: boolean;
 *   onClose: () => void;
 *   chatHistory: import('../../types').ChatMessage[];
 *   onSendMessage: (msg: string) => void;
 *   isBotTyping: boolean;
 * }} props
 */
const ChatbotModal = ({ isOpen, onClose, chatHistory, onSendMessage, isBotTyping }) => {
  const [input, setInput] = useState('');
  const messagesEndRef = useRef(null);

  useLayoutEffect(() => {
    if (isOpen) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatHistory, isBotTyping, isOpen]);

  const handleSubmit = (e) => {
    e.preventDefault();
    const trimmed = input.trim();
    if (!trimmed || isBotTyping) return;
    onSendMessage(trimmed);
    setInput('');
  };

  if (!isOpen) return null;

  return (
    // Backdrop
    <div
      className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-center items-end sm:items-center p-4"
      onClick={onClose}
      role="dialog"
      aria-modal="true"
      aria-label="LiftBot chat"
    >
      {/* Panel */}
      <div
        className="bg-slate-50 rounded-2xl w-full max-w-lg h-[70vh] flex flex-col shadow-2xl animate-slide-up"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <header className="p-4 border-b border-slate-200 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-brand-600 flex items-center justify-center text-white text-sm">≡ƒñû</div>
            <div>
              <h2 className="text-base font-bold text-slate-800 leading-none">LiftBot Assistant</h2>
              <p className="text-xs text-brand-600 font-medium">AI English Tutor</p>
            </div>
          </div>
          <button
            className="text-slate-400 hover:text-slate-600 transition-colors rounded-lg p-1"
            onClick={onClose}
            aria-label="Close chat"
          >
            <CloseIcon />
          </button>
        </header>

        {/* Messages */}
        <main className="flex-grow overflow-y-auto p-4 flex flex-col gap-3">
          {chatHistory.length === 0 && (
            <div className="text-center text-slate-400 text-sm mt-8">
              <div className="text-4xl mb-3">≡ƒæï</div>
              <p>Hi! I'm LiftBot. Ask me anything about English grammar, vocabulary, or how to use this app!</p>
            </div>
          )}
          {chatHistory.map((msg, index) => (
            <div
              key={index}
              className={`max-w-[80%] p-3 rounded-2xl leading-normal text-sm ${
                msg.role === 'user'
                  ? 'bg-brand-600 text-white self-end rounded-br-md'
                  : 'bg-white border border-slate-200 text-slate-800 self-start rounded-bl-md shadow-sm'
              }`}
            >
              {msg.text}
            </div>
          ))}
          {isBotTyping && (
            <div className="bg-white border border-slate-200 self-start rounded-bl-md p-3 rounded-2xl shadow-sm flex gap-1 items-center">
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        {/* Input */}
        <footer className="p-4 border-t border-slate-200">
          <form onSubmit={handleSubmit} className="flex gap-2">
            <input
              id="chatbot-input"
              type="text"
              className="flex-grow px-4 py-2.5 rounded-xl border border-slate-300 bg-white text-slate-800
                         placeholder:text-slate-400 focus:ring-2 focus:ring-brand-300 focus:border-brand-400 outline-none
                         transition-shadow text-sm"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask an English questionΓÇª"
              autoComplete="off"
              aria-label="Chat message"
            />
            <button
              type="submit"
              className="btn-primary rounded-xl px-4"
              disabled={isBotTyping || !input.trim()}
              aria-label="Send message"
            >
              <SendIcon />
            </button>
          </form>
        </footer>
      </div>
    </div>
  );
};

export default ChatbotModal;

import { useMemo } from 'react';
import Card from '../ui/Card';
import SparklineChart from '../ui/SparklineChart';
import { CloseIcon } from '../ui/Icons';

/**
 * @param {{
 *   isOpen: boolean; onClose: () => void;
 *   streak: import('../../types').Streak;
 *   records: import('../../types').PracticeRecord[];
 *   goals: import('../../types').Goal[];
 *   lang: string; setLang: (l: string) => void;
 *   completionPercentage: number;
 *   userName: string; setUserName: (n: string) => void;
 *   englishLevel: string; setEnglishLevel: (l: string) => void;
 * }} props
 */
const ProfileModal = ({
  isOpen, onClose, streak, records, goals,
  lang, setLang, completionPercentage,
  userName, setUserName, englishLevel, setEnglishLevel,
}) => {
  const wpmSeries = useMemo(
    () => records.filter((r) => r.type === 'typing').map((r) => r.wpm),
    [records],
  );
  const accSeries = useMemo(
    () => records.filter((r) => r.type === 'typing').map((r) => r.accuracy),
    [records],
  );

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-center items-center p-4"
      onClick={onClose}
      role="dialog"
      aria-modal="true"
      aria-label="User profile"
    >
      <div
        className="bg-slate-50 rounded-3xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl animate-slide-up"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Top bar */}
        <div className="flex justify-between items-start mb-6">
          <div>
            <p className="text-sm font-medium text-slate-500 mb-1">Welcome back,</p>
            <input
              id="profile-name-input"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              placeholder="Enter your name"
              className="text-3xl font-bold text-slate-800 bg-transparent focus:bg-slate-100 rounded-lg p-2 -ml-2 w-full outline-none transition-colors focus:ring-2 focus:ring-brand-300"
              aria-label="Your name"
            />
          </div>
          <button className="text-slate-400 hover:text-slate-600 transition-colors p-1 rounded-lg mt-1" onClick={onClose} aria-label="Close profile">
            <CloseIcon />
          </button>
        </div>

        {/* Streak + Goal progress */}
        <Card className="mb-6">
          <div className="flex justify-around items-center text-center">
            <div>
              <div className="text-4xl font-extrabold text-brand-600">{streak?.count || 0}</div>
              <div className="text-sm text-slate-500 mt-1">≡ƒöÑ Day Streak</div>
            </div>
            <div className="h-16 w-px bg-slate-200" />
            <div className="w-1/2">
              <div className="text-sm text-slate-500 mb-2">Daily Goal Progress</div>
              <div className="w-full bg-slate-200 rounded-full h-3 overflow-hidden">
                <div
                  className="bg-brand-600 h-3 rounded-full transition-all duration-500"
                  style={{ width: `${completionPercentage}%` }}
                  role="progressbar"
                  aria-valuenow={completionPercentage}
                  aria-valuemin={0}
                  aria-valuemax={100}
                />
              </div>
              <div className="text-xs text-slate-400 mt-1">{completionPercentage}% complete</div>
            </div>
          </div>
        </Card>

        {/* Daily goals */}
        {goals.length > 0 && (
          <div className="mb-6">
            <h3 className="text-base font-bold text-slate-700 mb-3">Today's Goals</h3>
            <div className="space-y-2">
              {goals.map((g) => (
                <div key={g.id} className="flex items-center gap-3">
                  <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors ${g.done ? 'border-brand-500 bg-brand-500' : 'border-slate-300'}`}>
                    {g.done && <span className="text-white text-xs">Γ£ô</span>}
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between text-sm">
                      <span className={g.done ? 'text-brand-700 font-medium' : 'text-slate-600'}>{g.label}</span>
                      <span className="text-slate-400">{g.progress}/{g.target}</span>
                    </div>
                    <div className="w-full bg-slate-200 rounded-full h-1.5 mt-1">
                      <div className="bg-brand-500 h-1.5 rounded-full transition-all duration-300" style={{ width: `${Math.min(100, (g.progress / g.target) * 100)}%` }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Performance charts */}
        <div className="mb-6">
          <h3 className="text-base font-bold text-slate-700 mb-3">Performance Trends</h3>
          <div className="grid md:grid-cols-2 gap-4">
            <Card>
              <div className="text-sm font-medium text-slate-500 mb-2">WPM Trend (Last {wpmSeries.length})</div>
              <SparklineChart values={wpmSeries} />
            </Card>
            <Card>
              <div className="text-sm font-medium text-slate-500 mb-2">Accuracy Trend</div>
              <SparklineChart values={accSeries} color="#10b981" />
            </Card>
          </div>
        </div>

        {/* Settings */}
        <div>
          <h3 className="text-base font-bold text-slate-700 mb-3">Settings</h3>
          <Card>
            <div className="grid sm:grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-slate-600 block mb-1" htmlFor="english-level-select">English Level</label>
                <select
                  id="english-level-select"
                  value={englishLevel}
                  onChange={(e) => setEnglishLevel(e.target.value)}
                  className="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white focus:ring-2 focus:ring-brand-300 focus:border-brand-400 outline-none"
                >
                  <option value="beginner">Beginner</option>
                  <option value="intermediate">Intermediate</option>
                  <option value="advanced">Advanced</option>
                </select>
              </div>
              <div>
                <label className="text-sm font-medium text-slate-600 block mb-1" htmlFor="native-lang-select">Native Language</label>
                <select
                  id="native-lang-select"
                  value={lang}
                  onChange={(e) => setLang(e.target.value)}
                  className="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white focus:ring-2 focus:ring-brand-300 focus:border-brand-400 outline-none"
                >
                  <option value="hi">Hindi</option>
                  <option value="te">Telugu</option>
                </select>
              </div>
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default ProfileModal;

import { useState, useEffect, useCallback, useRef } from 'react';
import Card from '../ui/Card';
import { MicIcon, RestartIcon, SpeakerIcon, CloseIcon } from '../ui/Icons';
import { similarityPct } from '../../utils';

const SpeechRecognitionAPI =
  typeof window !== 'undefined'
    ? window.SpeechRecognition || window.webkitSpeechRecognition
    : null;
const isSpeechRecognitionSupported = !!SpeechRecognitionAPI;

const getColorForScore = (score) => {
  if (score >= 85) return 'bg-green-100 text-green-800';
  if (score >= 60) return 'bg-orange-100 text-orange-800';
  return 'bg-red-100 text-red-800';
};

/**
 * @param {{
 *   text: string;
 *   onSessionComplete: (summary: Object) => void;
 * }} props
 */
const PronouncePractice = ({ text, onSessionComplete }) => {
  const [isListening,      setIsListening]      = useState(false);
  const [transcript,       setTranscript]       = useState('');
  const [finalTranscript,  setFinalTranscript]  = useState('');
  const [score,            setScore]            = useState(null);
  const [wordScores,       setWordScores]       = useState(null);
  const [error,            setError]            = useState(null);
  const [ttsInput,         setTtsInput]         = useState('');
  const [isSpeaking,       setIsSpeaking]       = useState(false);

  const recognitionRef       = useRef(null);
  const utteranceRefTTS      = useRef(null);
  const shouldProcessOnEnd   = useRef(false);

  const reset = useCallback(() => {
    if (recognitionRef.current) {
      recognitionRef.current.onresult = null;
      recognitionRef.current.onend    = null;
      recognitionRef.current.onerror  = null;
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
    setIsListening(false);
    setTranscript('');
    setFinalTranscript('');
    setScore(null);
    setWordScores(null);
    setError(null);
    shouldProcessOnEnd.current = false;
  }, []);

  // Reset when story changes
  useEffect(() => { reset(); }, [text, reset]);

  // Cleanup on unmount
  useEffect(() => () => {
    recognitionRef.current?.stop();
    window.speechSynthesis?.cancel();
  }, []);

  // Process transcript once listening stops
  useEffect(() => {
    if (!isListening && shouldProcessOnEnd.current) {
      const result = finalTranscript.trim();
      if (result) {
        const calculatedScore = similarityPct(text, result);
        setScore(calculatedScore);

        const originalTokens = text.split(/\s+/).filter(Boolean);
        const spokenTokens   = result.split(/\s+/).filter(Boolean);

        const calculatedWordScores = originalTokens.map((originalToken, index) => {
          const spokenToken   = spokenTokens[index] || '';
          const cleanOriginal = originalToken.toLowerCase().replace(/[.,]/g, '');
          const cleanSpoken   = spokenToken.toLowerCase().replace(/[.,]/g, '');
          return { word: originalToken, score: similarityPct(cleanOriginal, cleanSpoken) };
        });
        setWordScores(calculatedWordScores);

        const incorrectWords = calculatedWordScores
          .filter((ws) => ws.score < 75)
          .map((ws) => ws.word.toLowerCase().replace(/[.,]/g, ''));

        onSessionComplete({
          score: calculatedScore,
          wordScores: calculatedWordScores,
          incorrectWords: [...new Set(incorrectWords)],
        });
      }
      shouldProcessOnEnd.current = false;
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isListening, finalTranscript]);

  const handleSpeak = useCallback(() => {
    if (!window.speechSynthesis || !ttsInput.trim()) return;

    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      utteranceRefTTS.current = null;
      return;
    }
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(ttsInput);
    utterance.lang    = 'en-US';
    utterance.onstart = () => setIsSpeaking(true);
    utterance.onend   = () => { setIsSpeaking(false); utteranceRefTTS.current = null; };
    utterance.onerror = (e) => {
      if (e.error !== 'interrupted') console.error('TTS error:', e.error);
      setIsSpeaking(false);
      utteranceRefTTS.current = null;
    };
    utteranceRefTTS.current = utterance;
    window.speechSynthesis.speak(utterance);
  }, [ttsInput, isSpeaking]);

  const handleListen = useCallback(() => {
    if (isListening) {
      shouldProcessOnEnd.current = true;
      recognitionRef.current?.stop();
    } else {
      if (!isSpeechRecognitionSupported) {
        setError('Speech recognition is not supported in this browser. Please try Chrome or Edge.');
        return;
      }
      reset();

      const recognition = new SpeechRecognitionAPI();
      recognitionRef.current = recognition;
      recognition.continuous      = true;
      recognition.interimResults  = true;
      recognition.lang            = 'en-US';

      recognition.onresult = (event) => {
        let interim = '';
        let final   = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          if (event.results[i].isFinal) {
            final += event.results[i][0].transcript;
          } else {
            interim += event.results[i][0].transcript;
          }
        }
        setTranscript(interim);
        if (final.trim()) setFinalTranscript((prev) => (prev ? `${prev} ` : '') + final.trim());
      };

      recognition.onerror = (event) => {
        if (event.error === 'not-allowed') {
          setError('Microphone access was denied. Please allow microphone access in your browser settings.');
        } else if (event.error === 'no-speech') {
          setError('No speech detected. Please make sure your microphone is working.');
        } else {
          setError(`An error occurred: ${event.error}. Please try again.`);
        }
        setIsListening(false);
      };

      recognition.onend = () => setIsListening(false);
      recognition.start();
      setIsListening(true);
    }
  }, [isListening, reset]);

  return (
    <Card>
      {/* TTS section */}
      <div className="pb-4 border-b border-slate-200 mb-4">
        <h3 className="text-lg font-bold text-slate-800">Hear it First</h3>
        <p className="text-sm text-slate-500 mt-0.5 mb-3">Type a word or sentence to hear how it's pronounced.</p>
        <div className="flex gap-2">
          <div className="relative flex-grow">
            <input
              id="tts-input"
              type="text"
              className="w-full px-3 py-2 pr-10 rounded-xl border border-slate-300 bg-white text-slate-800 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-300 focus:border-brand-400 outline-none"
              value={ttsInput}
              onChange={(e) => setTtsInput(e.target.value)}
              placeholder="e.g. The quick brown foxΓÇª"
              aria-label="Text to pronounce"
            />
            {ttsInput && (
              <button
                type="button"
                onClick={() => setTtsInput('')}
                className="absolute right-0 top-0 h-full px-3 flex items-center text-slate-400 hover:text-slate-600"
                aria-label="Clear input"
              >
                <CloseIcon className="w-4 h-4" />
              </button>
            )}
          </div>
          <button
            onClick={handleSpeak}
            disabled={!ttsInput.trim()}
            className="btn-primary rounded-xl"
            id="tts-speak-btn"
          >
            <SpeakerIcon />
            <span>{isSpeaking ? 'Stop' : 'Listen'}</span>
          </button>
        </div>
      </div>

      {/* Practice section */}
      <div>
        <h2 className="text-xl font-bold text-slate-800">Pronunciation Practice</h2>
        <p className="text-sm text-slate-500 mt-0.5 mb-4">Click the mic and read the text below aloud.</p>

        {/* Story text with scored colouring */}
        <div
          className="p-5 bg-brand-50 rounded-xl text-xl sm:text-2xl leading-relaxed tracking-wide border-2 border-dashed border-slate-300 mb-4"
          aria-label="Text to read aloud"
        >
          {wordScores ? (
            wordScores.map((info, idx) => (
              <span key={idx}>
                <span className={`rounded-md px-1 py-0.5 transition-colors duration-300 ${getColorForScore(info.score)}`}>
                  {info.word}
                </span>
                {idx < wordScores.length - 1 ? ' ' : ''}
              </span>
            ))
          ) : (
            text
          )}
        </div>

        {/* Controls */}
        <div className="flex flex-wrap gap-4 items-center min-h-[40px]">
          {error ? (
            <div className="w-full flex flex-col sm:flex-row items-start gap-4">
              <div className="text-sm text-red-600 bg-red-50 p-3 rounded-xl w-full">
                <strong>Oops!</strong> {error}
              </div>
              <button onClick={handleListen} className="btn-primary flex-shrink-0" id="pronounce-retry-btn">
                <RestartIcon />
                Try Again
              </button>
            </div>
          ) : (
            <>
              <button
                onClick={handleListen}
                disabled={!isSpeechRecognitionSupported || isSpeaking}
                className={`btn-primary ${isListening ? 'bg-red-500 hover:bg-red-600' : ''}`}
                id="pronounce-listen-btn"
              >
                <MicIcon />
                <span>{isListening ? 'Stop & See Score' : 'Start Listening'}</span>
              </button>
              <button onClick={reset} disabled={isSpeaking} className="btn-ghost" id="pronounce-reset-btn">
                <RestartIcon />
                Reset
              </button>
              {score !== null && (
                <div className="ml-auto text-center sm:text-right">
                  <div className="text-xs text-slate-500 uppercase tracking-wide">Overall Score</div>
                  <div className={`text-3xl font-extrabold ${score > 80 ? 'text-green-600' : 'text-slate-700'}`}>
                    {score}%
                  </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* Live transcript */}
        {!error && (transcript || finalTranscript) && (
          <div className="mt-4 p-4 bg-white border border-slate-200 rounded-xl">
            <h4 className="text-sm font-semibold text-slate-600 mb-1">What I heard:</h4>
            <p className="text-slate-700">
              {finalTranscript}
              <span className="text-slate-400">{transcript}</span>
            </p>
          </div>
        )}

        {/* Browser unsupported warning */}
        {!isSpeechRecognitionSupported && !error && (
          <div className="mt-4 text-sm text-yellow-700 bg-yellow-50 border border-yellow-200 p-3 rounded-xl">
            ΓÜá∩╕Å Speech recognition is not supported in your browser. Please try Chrome or Edge for this feature.
          </div>
        )}
      </div>
    </Card>
  );
};

export default PronouncePractice;

import Card from './Card';

/**
 * Shows a personalised exercise card after a practice session.
 * @param {{ exercise: string | null; onDismiss: () => void }} props
 */
const PersonalizedExercise = ({ exercise, onDismiss }) => {
  if (!exercise) return null;

  return (
    <Card className="mt-4 border-brand-500 border-2 animate-fade-in">
      <div className="flex justify-between items-center mb-2">
        <h3 className="text-lg font-bold text-brand-700">Personalised Practice Γ£¿</h3>
        <button
          onClick={onDismiss}
          className="text-sm font-semibold text-slate-500 hover:text-slate-800 transition-colors"
          aria-label="Dismiss personalised exercise"
        >
          Dismiss
        </button>
      </div>
      <p className="text-slate-600 mb-3">
        Here's a special exercise based on your last session to help you improve:
      </p>
      <div className="p-4 bg-brand-50 rounded-xl text-xl leading-relaxed text-slate-700">
        {exercise}
      </div>
    </Card>
  );
};

export default PersonalizedExercise;

import { useNavigate } from 'react-router-dom';
import Card from '../components/ui/Card';

const sections = [
  {
    icon: '≡ƒôû',
    title: 'Learn Stories',
    content: 'Read engaging stories generated just for you. Tap the "New Story" button for fresh content. Long-press any word to see its translation in your native language. Use the "Listen" button to hear the story narrated.',
  },
  {
    icon: 'Γî¿∩╕Å',
    title: 'Practice Typing',
    content: 'Hone your keyboard skills by typing out the stories. You\'ll get real-time feedback on your speed (WPM) and accuracy. After each session, receive a personalised exercise if you struggled with certain words.',
  },
  {
    icon: '≡ƒöè',
    title: 'Practice Pronunciation',
    content: 'Use "Hear it First" to hear any word or sentence spoken. Then click the microphone and read the story aloud ΓÇö our AI scores your pronunciation and highlights words you can improve on.',
  },
  {
    icon: '≡ƒñû',
    title: 'Meet LiftBot',
    content: 'Have a question? Click the chat icon in the bottom-right corner. LiftBot is your friendly AI assistant, ready to help with grammar, vocabulary, or how to use the app.',
  },
  {
    icon: '≡ƒæñ',
    title: 'Track Your Progress',
    content: 'Click the profile icon in the top-right. Set your name, change your English level, see your daily streak, view goal progress, and track WPM & accuracy trends over time.',
  },
];

const HelpPage = () => {
  const navigate = useNavigate();

  return (
    <div className="max-w-xl mx-auto mt-6 mb-6 animate-fade-in">
      <div className="mb-6">
        <button
          onClick={() => navigate('/')}
          id="help-back-btn"
